// HTML escape helper (XSS protection)
const esc = (s = '') => String(s)
  .replaceAll('&', '&amp;')
  .replaceAll('<', '&lt;')
  .replaceAll('>', '&gt;')
  .replaceAll('"', '&quot;')
  .replaceAll("'", '&#39;');

const row = $input.first().json;
const pick = (...keys) => {
  for (const k of keys) {
    if (row[k] !== undefined && row[k] !== null && String(row[k]).trim() !== '') return row[k];
  }
  return '';
};

const config = {
  companyName: row.companyName || 'Your Company Inc.',
  logoUrl: row.companyLogoUrl || '',
  taxRate: Number(row.taxRate) || 0,
  currency: row.currencySymbol || '$'
};

const orderNumber = pick('Order Number', 'OrderNumber', 'order_number') || 'INV-' + Date.now();
const customerName = pick('Customer Name', 'CustomerName', 'customer_name') || 'Customer';
const customerEmail = pick('Customer Email', 'CustomerEmail', 'customer_email');
const customerAddress = pick('Customer Address', 'CustomerAddress', 'customer_address');
const dueDate = pick('Due Date', 'DueDate', 'due_date');
const notes = pick('Notes', 'notes');

let items = [];
try {
  const raw = pick('Items', 'items');
  items = typeof raw === 'string' ? JSON.parse(raw) : (Array.isArray(raw) ? raw : []);
} catch (e) {
  throw new Error('The Items column must contain a JSON array like [{"name":"Widget","quantity":2,"price":9.99}] — got: ' + pick('Items', 'items'));
}
if (!items.length) {
  throw new Error('No line items found in the Items column for order ' + orderNumber);
}

let itemsHtml = '';
let subtotal = 0;
for (const item of items) {
  const qty = Number(item.quantity) || 0;
  const price = Number(item.price) || 0;
  const lineTotal = qty * price;
  subtotal += lineTotal;
  itemsHtml += '<tr><td>' + esc(item.name) + '</td><td>' + qty + '</td><td>' + config.currency + price.toFixed(2) + '</td><td>' + config.currency + lineTotal.toFixed(2) + '</td></tr>';
}

const tax = subtotal * config.taxRate;
const total = subtotal + tax;
const taxHtml = config.taxRate > 0
  ? '<p class="right">Tax (' + (config.taxRate * 100).toFixed(0) + '%): ' + config.currency + tax.toFixed(2) + '</p>'
  : '';
const logoHtml = config.logoUrl
  ? '<img src="' + esc(config.logoUrl) + '" style="max-height:60px;max-width:200px;" alt="Logo">'
  : '';
const dueHtml = dueDate ? '<p><strong>Due Date:</strong> ' + esc(dueDate) + '</p>' : '';
const addressHtml = customerAddress ? '<p><strong>Address:</strong> ' + esc(customerAddress) + '</p>' : '';
const notesHtml = notes ? '<div class="notes"><strong>Notes:</strong><br>' + esc(notes) + '</div>' : '';

const html = `<!DOCTYPE html>
<html>
<head>
<style>
  body { font-family: Arial, sans-serif; padding: 40px; color: #1e293b; }
  .header { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 24px; }
  h1 { margin: 0 0 4px 0; } h2 { color: #64748b; margin: 0; font-weight: 600; }
  table { width: 100%; border-collapse: collapse; margin: 20px 0; }
  th, td { padding: 10px; text-align: left; border-bottom: 1px solid #e2e8f0; }
  th { background: #f1f5f9; }
  .right { text-align: right; }
  .bold { font-weight: bold; font-size: 18px; }
  .notes { margin-top: 30px; padding: 15px; background: #f8fafc; border-left: 3px solid #cbd5e1; }
</style>
</head>
<body>
  <div class="header">
    <div><h1>${esc(config.companyName)}</h1><h2>INVOICE</h2></div>
    ${logoHtml}
  </div>
  <p><strong>Invoice #:</strong> ${esc(orderNumber)}</p>
  <p><strong>Date:</strong> ${new Date().toISOString().slice(0, 10)}</p>
  ${dueHtml}
  <p><strong>Bill To:</strong> ${esc(customerName)}</p>
  ${addressHtml}
  <p><strong>Email:</strong> ${esc(customerEmail)}</p>
  <table>
    <tr><th>Item</th><th>Qty</th><th>Price</th><th>Total</th></tr>
    ${itemsHtml}
  </table>
  <p class="right">Subtotal: ${config.currency}${subtotal.toFixed(2)}</p>
  ${taxHtml}
  <p class="right bold">Total: ${config.currency}${total.toFixed(2)}</p>
  ${notesHtml}
</body>
</html>`;

return [{
  json: {
    html,
    orderNumber,
    customerName,
    customerEmail,
    invoiceFilename: orderNumber + '.pdf',
    emailSubject: (row.emailSubjectPrefix || 'Your invoice') + ' — ' + orderNumber
  }
}];
